import{_ as a,o as l,c as i,a0 as t}from"./chunks/framework.CSGB4SNl.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/八股文day01.md","filePath":"java/eight-legged essay/八股文day01.md"}'),o={name:"java/eight-legged essay/八股文day01.md"};function r(n,e,s,d,_,c){return l(),i("div",null,[...e[0]||(e[0]=[t('<h4 id="volatile关键字" tabindex="-1">volatile关键字 <a class="header-anchor" href="#volatile关键字" aria-label="Permalink to &quot;volatile关键字&quot;">​</a></h4><ol><li>可见性、静止指令重排</li><li>一个线程改一个线程可以看到他的改动，适用于一写多读</li><li>为什么适用于一写多读，而不是多写多读呢，因为两个线程同时去改的话，比如读取到为0，那么当一个改完，另一个已经把0写入自己的工作内存中了</li><li>也有可能是一个线程写完还没刷回主内存中时，另一个也写了，导致写覆盖问题</li><li>不保证原子性、只保证引用对象的可见性，对如数组中每个元素不保证可见性，可使用AtomicIntegerArray类来保证元素可见性</li><li>正常来说它不会失效，只会误用情况，在jvm32位场景下读写long/double可能不是原子性的，引用对象还没被初始化的情况下可能失效</li><li>轻量是其不想其它那样涉及锁竞争、线程阻塞等</li></ol><h4 id="synchronized关键字-简要回答版" tabindex="-1">synchronized关键字-简要回答版 <a class="header-anchor" href="#synchronized关键字-简要回答版" aria-label="Permalink to &quot;synchronized关键字-简要回答版&quot;">​</a></h4><ol><li>原理就是依赖于jvm的监听器锁和对象头，会对修饰的区域加上标记，线程访问时会检查标记，然后执行进入和退出指令，进入拿锁，拿不到进入等待队列进行休息，等锁释放后进行唤醒执行</li><li>会自动处理异常</li><li>通过在加锁时清空各线程工作内存，就强制让每个线程重新从主内存中读取，实现可见性</li><li>可能导致线程阻塞方面、加锁方面开销</li></ol>',4)])])}const g=a(o,[["render",r]]);export{m as __pageData,g as default};
